entry main(x: Text) {
    resp = perform http.get("https://httpbin.org/json")
    if resp.ok {
        lines = split(resp.body, "\n")
        for line in lines {
            if "author" in line {
                parts = split(line, ":")
                if length(parts) >= 2 {
                    author = trim(parts[1])
                    author = replace(author, "\"", "")
                    author = replace(author, ",", "")
                    return author
                }
            }
        }
        return "author not found"
    }
    return "request failed"
}

entry main(x: Text) {
    resp = perform http.get("https://api.github.com/repos/anthropics/anthropic-sdk-python")
    body_text = resp.body
    lines = split(body_text, "\n")
    for line in lines {
        if starts_with(trim(line), "\"language\"") {
            parts = split(line, ":")
            if length(parts) >= 2 {
                value_part = trim(parts[1])
                cleaned = replace(value_part, "\"", "")
                cleaned = replace(cleaned, ",", "")
                return trim(cleaned)
            }
        }
    }
    return "not_found"
}

intent translate_to_korean(text: Text) -> Text {
    goal: translate_text_to_Korean
}

entry main(x: Text) {
    response = perform http.get("https://httpbin.org/json")
    body = response.body

    title_start = split(body, "\"title\": \"")
    if length(title_start) < 2 {
        return "error: title not found"
    }

    title_part = get(title_start, 1)
    title_end = split(title_part, "\"")
    title = get(title_end, 0)

    korean = translate_to_korean(title)
    return korean
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/numbers.txt")
