}

pure fn count_by_sentiment(reviews: [Text], sentiment: Text) -> Number {
    count = 0
    for r in reviews {
        if r == sentiment { count = count + 1 }
    }
    return count
}

intent classify_sentiment(review: Text) -> Text {
    goal: positive_or_negative
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    lines = split(trim(content), "\n")
    labels = []
    for line in lines {
        label = classify_sentiment(line)
        labels = append(labels, label)
    }
    pos = count_by_sentiment(labels, "positive")
    neg = count_by_sentiment(labels, "negative")
    return join(["positive=", to_text(pos), " negative=", to_text(neg)], "")
}

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

entry main(x: Text) {
    result = factorial(10)
    perform file.write("/tmp/heaal_e2_out/factorial.txt", to_text(result))
    return "done"
}

intent classify_sentiment(review: Text) -> Text {
    goal: positive_or_negative
}

pure fn filter_by_sentiment(reviews: [Text], sentiments: [Text], target: Text) -> [Text] {
    filtered = []
    for i in range(0, length(reviews)) {
        if get(sentiments, i) == target {
            filtered = append(filtered, get(reviews, i))
        }
    }
    return filtered
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    reviews = split(trim(content), "\n")

    sentiments = []
    for review in reviews {
        sentiment = classify_sentiment(review)
        sentiments = append(sentiments, sentiment)
    }

    positives = filter_by_sentiment(reviews, sentiments, "positive")
    negatives = filter_by_sentiment(reviews, sentiments, "negative")

    pos_text = join(positives, "\n")
    neg_text = join(negatives, "\n")

    pos_result = perform file.write("/tmp/heaal_e2_out/positives.txt", pos_text)
    neg_result = perform file.write("/tmp/heaal_e2_out/negatives.txt", neg_text)

    return "done"
}

pure fn classify_severity(line: Text) -> Text {
    lower_line = lower(line)
    if starts_with(lower_line, "error") { return "ERROR" }
    if starts_with(lower_line, "warn") { return "WARN" }
    return "INFO"
}

pure fn count_severity(lines: [Text], target: Text) -> Number {
    count = 0
    for line in lines {
        severity = classify_severity(line)
        if severity == target { count = count + 1 }
    }
    return count
}

entry main(x: Text) {
    content = perform file.read("/tmp/heaal_e2_data/log.txt")
    lines = split(trim(content), "\n")
    info_count = count_severity(lines, "INFO")
    warn_count = count_severity(lines, "WARN")
    error_count = count_severity(lines, "ERROR")
    return join(["INFO=", to_text(info_count), " WARN=", to_text(warn_count), " ERROR=", to_text(error_count)], "")
}

